var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"대체 뭐가 어떻게 돌아가고 있는 거야.","JPN":"いったい何がどうなってやがる。","ENG":"I don’t understand.","TWN":"現在是什麼展開？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"증거를 찾으러 갔더니 집은 불타고 있고, 하필이면 그때 장로가 당주들을 데리고 나타나서 공범으로 몰린다고?","JPN":"証拠を探しに行ったら家は燃えてるし、よりによってその時に\\n長老が当主たちを連れて現れて、共犯にされるなんて。","ENG":"All we wanted was to find a piece of evidence, but the cabin was already burning, and elders rush in with the family leaders to blame us for what happened.","TWN":"去找證據，結果發現房子被縱火，然後說時遲，那時快，長老剛好就帶著堂主們出現，誣賴我們是共犯？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"게다가… 저 할멈은 언제부터 저렇게 아귀 힘이 셌던 거야?","JPN":"にしても……あのクソババアはいつの間にあんなに強くなったんだ？","ENG":"And... I didn’t know Sayo was that strong.","TWN":"還有…那個老太婆力氣怎麼變這麼大？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"불을 지른 건 대체 누구였을까?","JPN":"火を付けたのはいったい誰だろう？","ENG":"Who could have set the fire?","TWN":"到底是誰縱的火？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"쳇, 아무도 밝혀내려고 하지 않을걸? 연합은 우리가 한 짓이라고 멋대로 확정 지었으니까.","JPN":"チッ、そんなの誰も突き止めようとしないと思うぜ？\\n連合はオレたちがやったことだって決めつけてやがるからな。","ENG":"Bah, no one will care. The Alliance already concluded that we’re the ones who did it.","TWN":"嗟，根本什麼也查不出來吧？反正聯盟認定是我們做的。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"우리가 밝혀내야지.","JPN":"オレたちで明かさないと。","ENG":"That’s why we have to find the real culprit.","TWN":"我們必須替自己洗刷冤屈！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그러려면 일단 여기서 나가야 할 텐데, 어쩌지?","JPN":"とりあえず、ここから出ないと何も始まらないな。どうしよう？","ENG":"To do that, we have to get out of here first. What do we do?","TWN":"那我們得先從這裡出去吧？該怎麼做才好？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"훗, 뒤로 물러서라. 미나토.","JPN":"フッ……下がってろ、湊。","ENG":"Hah, step back, Minato.","TWN":"呼，南裕夏，你退開！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이 오오가미님을 가둘 수 있는 쇠창살은 없다는 걸, 똑똑히 보여주지.","JPN":"この大神様を閉じ込めておける鉄格子なんて存在しないことを見せてやろう。","ENG":"There is no cage in the world that can stop me.","TWN":"給我看清楚了，沒有鐵窗能關住我這個大神！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"흡!!!","JPN":"フッ！！","ENG":"Hup!!!","TWN":"嚇！！！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"끄아아아앗!! 열려라!","JPN":"うおおおおっ！！　開け！","ENG":"Hurp!! Open!","TWN":"嚇啊啊！！給我打開！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키, 그러다 건물이 무너지는 거 아냐?","JPN":"雅紀、その調子だと建物ごと壊れちゃいそうだよ？","ENG":"Masaki, I think you’ll bring down the whole building before we get out of here.","TWN":"雅紀，這棟建築物不會倒吧？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"헉, 헉…… 대체 뭘로 만들었길래 이렇게 튼튼한 거야?","JPN":"はあ、はあ……いったい何で作ればこんな頑丈になるんだ？","ENG":"*Pant* What is this thing made of?","TWN":"呼呼……到底是用什麼蓋的，這麼扎實？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"너무 애쓰지 마세요.","JPN":"難しいと思いますよ。","ENG":"Stop exerting yourself.","TWN":"請不要白費力氣。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그건 구 관리국 시절, 카토리 가문에서 위험한 카운터를 격리하기 위해 만든 특수한 감옥이니까요.","JPN":"それは旧管理局時代、香取家が危険なカウンターを\\n隔離するために作った特殊な監獄ですから。","ENG":"You’re in a special cage for dangerous Counters. It was made by Katori family during the Old Administration period.","TWN":"這是舊管理局時期，香取家族爲了隔離危險的制裁者，而打造的特殊監牢。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};